const basePremium = (item: Item): number => {
  if (item.type === "sword") {
    return 100;
  }
  return 0;
};

export const quote = (
  customer: { yearsWithMHPCO: number },
  items: Item[],
  isFollowUp: boolean
): number => {
  const premium = items.reduce((sum, item) => sum + basePremium(item), 0);
  return premium + PROCESSING_FEE;
};

